import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

export const Navigationhome = (props) => {
  const Nav = useNavigate();
  const [data, setData] = useState({
    profile: "",
    fname: "",
    lname: ""
  });

  useEffect(() => {
    axios.get(`https://space-club.onrender.com/getdata/${window.localStorage.getItem('user')}`)
      .then((res) => {
        setData({
          profile: res.data.profile,
          fname: res.data.fname,
          lname: res.data.lname
        });
      })
      .catch((error) => {
        console.error('Error fetching data:', error);
      });
  }, []);

  const logout = () => {
    Nav('/logout');
  };

  return (
    <nav className="navbar navbar-default navbar-fixed-top">
      <div className="container-fluid">
        <div className="navbar-header">
          <button
            type="button"
            className="navbar-toggle collapsed"
            data-toggle="collapse"
            data-target="#bs-example-navbar-collapse-1"
          >
            <span className="sr-only">Toggle navigation</span>{" "}
            <span className="icon-bar"></span>{" "}
            <span className="icon-bar"></span>{" "}
            <span className="icon-bar"></span>{" "}
          </button>
          <Link className="navbar-brand page-scroll" to="/home" id="navigationmain">
            <img src="https://space-club.onrender.com/img/nav_icon.jpg" alt="astec logo"/>
            <h1>ASTEC</h1>
          </Link>{" "}
        </div>

        <div className="collapse navbar-collapse" id="bs-example-navbar-collapse-1">
          <ul className="nav navbar-nav navbar-right">
            <li><Link to="/home#features" className="page-scroll">Events</Link></li>
            <li><Link to="/home#about" className="page-scroll">Our AIM</Link></li>
            <li><Link to="/home#services" className="page-scroll">COLLABORATIONS</Link></li>
            <li><Link to="/home#portfolio" className="page-scroll">Gallery</Link></li>
            <li><Link to="/home#testimonials" className="page-scroll">Testimonials</Link></li>
            <li><Link to="/home#team" className="page-scroll">Team</Link></li>
            <li><Link to="/home#contact" className="page-scroll">Contact</Link></li>
            <li>
              <div className="dropdown">
                <img src={`https://space-club.onrender.com/profile/${data.profile}`} id="profileimg" className="dropdown-toggle" type="button" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false"/>
                <div className="dropdown-menu" aria-labelledby="dropdownMenuButton" style={{ textAlign: 'center', padding: '20px' }}>
                  <img src={`https://space-club.onrender.com/profile/${data.profile}`} id="profilesubimg" alt="profile"/>
                  <h3>{data.fname} {data.lname}</h3>
                  <Link to="/home" className="dropdown-item" id="profilea">HOME</Link><br/>
                  <Link to="/projects" className="dropdown-item" id="profilea">PROJECTS</Link><br/>
                  <Link to="/teams" className="dropdown-item" id="profilea">TEAMS</Link><br/>
                  <Link to="/settings" className="dropdown-item" id="profilea">SETTINGS</Link><br/>
                  <button className="dropdown-item" id="profilea" onClick={logout}>LOGOUT</button>
                </div>
              </div>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  );
};
